import { useState, useEffect } from 'react';
import { BrowserRouter as Router, Routes, Route } from 'react-router-dom';
import { Toaster } from 'react-hot-toast';
import toast from 'react-hot-toast';
import Dashboard from './components/Dashboard';
import PatientProfile from './components/PatientProfile';
import AnalyticsDashboard from './components/AnalyticsDashboard';
import LoginPage from './components/LoginPage';
import LandingPage from './components/LandingPage';
import SettingsPanel from './components/SettingsPanel';
import PluginPanel from './components/PluginPanel';
import APIDocsViewer from './components/APIDocsViewer';
import KeyboardShortcuts from './components/KeyboardShortcuts';
import DiagnosticLog from './components/DiagnosticLog';
import './App.css';

function App() {
  const [user, setUser] = useState(null);
  const [token, setToken] = useState(null);
  const [showLogin, setShowLogin] = useState(false);
  const [theme, setTheme] = useState(() => localStorage.getItem('vibrana_theme') || 'dark');

  // Apply theme
  useEffect(() => {
    document.documentElement.setAttribute('data-theme', theme);
    localStorage.setItem('vibrana_theme', theme);
  }, [theme]);

  // Restore session from localStorage
  useEffect(() => {
    const savedToken = localStorage.getItem('vibrana_token');
    const savedUser = localStorage.getItem('vibrana_user');
    if (savedToken && savedUser) {
      setToken(savedToken);
      setUser(JSON.parse(savedUser));
    }
  }, []);

  const handleLogin = (userData, tokenStr) => {
    setUser(userData);
    setToken(tokenStr);
  };

  const handleLogout = () => {
    setUser(null);
    setToken(null);
    localStorage.removeItem('vibrana_token');
    localStorage.removeItem('vibrana_user');
  };

  const toggleTheme = () => {
    setTheme(t => t === 'dark' ? 'light' : 'dark');
    toast.success(`Switched to ${theme === 'dark' ? 'light' : 'dark'} mode`);
  };

  const handleShortcutAction = (action) => {
    if (action === 'theme') toggleTheme();
    else if (action === 'scan') toast('Ctrl+S: Trigger scan from Dashboard', { icon: 'Γî¿∩╕Å' });
    else if (action === 'search') {
      const input = document.querySelector('.search-input, input[type="text"]');
      if (input) input.focus();
    }
  };

  // Show landing or login if not authenticated
  if (!user) {
    return (
      <>
        <Toaster position="top-right" toastOptions={{
          duration: 3000,
          style: { background: '#1f2b47', color: '#e2e8f0', border: '1px solid rgba(255,255,255,0.06)', borderRadius: '8px', fontSize: '0.85rem' },
          success: { iconTheme: { primary: '#50fa7b', secondary: '#0f0f1a' } },
          error: { iconTheme: { primary: '#ff5555', secondary: '#0f0f1a' } },
        }} />
        {showLogin ? (
          <div style={{ position: 'relative' }}>
            <button
              className="btn-back-to-landing"
              onClick={() => setShowLogin(false)}
            >
              ΓåÉ Back
            </button>
            <LoginPage onLogin={handleLogin} />
          </div>
        ) : (
          <LandingPage onGetStarted={() => setShowLogin(true)} />
        )}
      </>
    );
  }

  const PageWrapper = ({ children, title }) => (
    <div className="dashboard-container">
      <header className="dashboard-header">
        <h1>{title || 'Vibrana Overseer'}</h1>
        <div style={{ display: 'flex', gap: 8, alignItems: 'center' }}>
          <a href="/" className="btn btn-ghost btn-sm">ΓåÉ Dashboard</a>
          <button className="btn btn-ghost btn-sm" onClick={toggleTheme} title="Toggle theme">
            {theme === 'dark' ? 'ΓÿÇ∩╕Å' : '≡ƒîÖ'}
          </button>
        </div>
      </header>
      {children}
    </div>
  );

  return (
    <Router>
      <KeyboardShortcuts onAction={handleShortcutAction} />
      <Toaster
        position="top-right"
        toastOptions={{
          duration: 3000,
          className: 'toast-custom',
          style: {
            background: '#1f2b47',
            color: '#e2e8f0',
            border: '1px solid rgba(255,255,255,0.06)',
            borderRadius: '8px',
            fontSize: '0.85rem',
          },
          success: { iconTheme: { primary: '#50fa7b', secondary: '#0f0f1a' } },
          error: { iconTheme: { primary: '#ff5555', secondary: '#0f0f1a' } },
        }}
      />
      <Routes>
        <Route path="/" element={<Dashboard />} />
        <Route path="/patients/:id" element={<PatientProfile />} />
        <Route path="/analytics" element={
          <PageWrapper><AnalyticsDashboard /></PageWrapper>
        } />
        <Route path="/settings" element={
          <PageWrapper><SettingsPanel user={user} token={token} onLogout={handleLogout} /></PageWrapper>
        } />
        <Route path="/api-docs" element={
          <PageWrapper title="API Documentation"><APIDocsViewer /></PageWrapper>
        } />
        <Route path="/plugins" element={
          <PageWrapper title="Plugin Manager"><PluginPanel token={token} /></PageWrapper>
        } />
        <Route path="/diagnostic-logs" element={
          <PageWrapper title="Diagnostic Log"><DiagnosticLog /></PageWrapper>
        } />
      </Routes>
    </Router>
  );
}

export default App;

import React, { useState, useEffect } from 'react';
import { ArrowLeftRight, X, ChevronDown } from 'lucide-react';
import toast from 'react-hot-toast';

import { API } from '../config.js';

const ComparisonMode = ({ patientId, onClose }) => {
    const [scans, setScans] = useState([]);
    const [leftScan, setLeftScan] = useState(null);
    const [rightScan, setRightScan] = useState(null);

    useEffect(() => {
        if (patientId) {
            fetch(`${API}/patients/${patientId}`)
                .then(r => r.json())
                .then(data => {
                    const s = data.scans || [];
                    setScans(s);
                    if (s.length >= 2) {
                        setLeftScan(s[s.length - 2]);
                        setRightScan(s[s.length - 1]);
                    } else if (s.length === 1) {
                        setLeftScan(s[0]);
                    }
                })
                .catch(() => toast.error('Failed to load scans'));
        }
    }, [patientId]);

    const getStatusColor = (status) => {
        if (!status) return '#6272a4';
        if (status.includes('6')) return '#ff5555';
        if (status.includes('5')) return '#ffb86c';
        if (status.includes('Pathology')) return '#ff5555';
        return '#50fa7b';
    };

    const compareCounts = (left, right) => {
        if (!left?.counts || !right?.counts) return null;
        const diff = {};
        for (let i = 1; i <= 6; i++) {
            const lv = parseInt(left.counts[i] || 0);
            const rv = parseInt(right.counts[i] || 0);
            diff[i] = { left: lv, right: rv, change: rv - lv };
        }
        return diff;
    };

    const diff = compareCounts(leftScan, rightScan);

    const ScanSelector = ({ value, onChange, label }) => (
        <div className="compare-selector">
            <label>{label}</label>
            <select value={value?.id || ''} onChange={e => {
                const s = scans.find(s => s.id === e.target.value);
                onChange(s);
            }}>
                <option value="">Select scan...</option>
                {scans.map(s => (
                    <option key={s.id} value={s.id}>
                        {s.organ_name} ΓÇö {new Date(s.timestamp).toLocaleDateString()} ({s.status})
                    </option>
                ))}
            </select>
        </div>
    );

    const ScanCard = ({ scan, label }) => {
        if (!scan) return <div className="compare-card empty"><p>No scan selected</p></div>;
        return (
            <div className="compare-card">
                <div className="compare-card-header">
                    <span className="compare-label">{label}</span>
                    <span style={{ color: getStatusColor(scan.status) }}>{scan.status}</span>
                </div>
                <h4>{scan.organ_name}</h4>
                <p className="compare-date">{new Date(scan.timestamp).toLocaleString()}</p>
                <div className="compare-stats">
                    <div className="compare-stat">
                        <span>Total Points</span>
                        <strong>{scan.total_points || 0}</strong>
                    </div>
                    {scan.counts && Object.entries(scan.counts).map(([level, count]) => (
                        <div key={level} className="compare-stat">
                            <span>Level {level}</span>
                            <strong>{count}</strong>
                        </div>
                    ))}
                </div>
                {scan.notes && <p className="compare-notes">≡ƒô¥ {scan.notes}</p>}
            </div>
        );
    };

    return (
        <div className="comparison-overlay" onClick={onClose}>
            <div className="comparison-modal" onClick={e => e.stopPropagation()}>
                <div className="comparison-header">
                    <h3><ArrowLeftRight size={16} /> Scan Comparison</h3>
                    <button className="btn btn-ghost btn-sm" onClick={onClose}><X size={14} /></button>
                </div>

                <div className="compare-selectors">
                    <ScanSelector value={leftScan} onChange={setLeftScan} label="Baseline" />
                    <ArrowLeftRight size={16} className="compare-arrow" />
                    <ScanSelector value={rightScan} onChange={setRightScan} label="Current" />
                </div>

                <div className="compare-grid">
                    <ScanCard scan={leftScan} label="Baseline" />
                    <ScanCard scan={rightScan} label="Current" />
                </div>

                {diff && (
                    <div className="compare-diff">
                        <h4>Change Analysis</h4>
                        <div className="diff-bars">
                            {Object.entries(diff).map(([level, d]) => (
                                <div key={level} className="diff-row">
                                    <span className="diff-label">L{level}</span>
                                    <div className="diff-bar-container">
                                        <div className="diff-bar-left" style={{ width: `${Math.min(d.left * 8, 100)}%` }} />
                                        <div className="diff-bar-right" style={{ width: `${Math.min(d.right * 8, 100)}%` }} />
                                    </div>
                                    <span className={`diff-change ${d.change > 0 ? 'up' : d.change < 0 ? 'down' : ''}`}>
                                        {d.change > 0 ? '+' : ''}{d.change}
                                    </span>
                                </div>
                            ))}
                        </div>
                        <div className="diff-summary">
                            {(rightScan?.total_points || 0) > (leftScan?.total_points || 0) ? (
                                <span className="diff-trend up">Γåæ Entropy increased by {(rightScan?.total_points || 0) - (leftScan?.total_points || 0)} points</span>
                            ) : (rightScan?.total_points || 0) < (leftScan?.total_points || 0) ? (
                                <span className="diff-trend down">Γåô Entropy decreased by {(leftScan?.total_points || 0) - (rightScan?.total_points || 0)} points</span>
                            ) : (
                                <span className="diff-trend">No change in total entropy</span>
                            )}
                        </div>
                    </div>
                )}
            </div>
        </div>
    );
};

export default ComparisonMode;

import React, { useState, useEffect, useRef } from 'react';
import { useNavigate } from 'react-router-dom';
import toast from 'react-hot-toast';
import { ChevronDown, ChevronRight, Wrench, Activity } from 'lucide-react';
import ControlPanel from './ControlPanel';
import LiveMonitor from './LiveMonitor';
import PatientManager from './PatientManager';
import StatsWidgets from './StatsWidgets';
import CVTools from './CVTools';
import MacroManager from './MacroManager';
import LiveEntropyCounter from './LiveEntropyCounter';
import ScreenWatcherPanel from './ScreenWatcherPanel';
import '../App.css';

import { LOCAL_API as API } from '../config.js';

/* ΓöÇΓöÇ Ambient VFX Canvas ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ */
const AmbientVFX = () => {
    const canvasRef = useRef(null);

    useEffect(() => {
        const canvas = canvasRef.current;
        if (!canvas) return;
        const ctx = canvas.getContext('2d');
        let animId;

        const resize = () => {
            canvas.width = window.innerWidth;
            canvas.height = window.innerHeight;
        };
        resize();
        window.addEventListener('resize', resize);

        // Floating orbs
        const orbs = Array.from({ length: 5 }, () => ({
            x: Math.random() * canvas.width,
            y: Math.random() * canvas.height,
            r: Math.random() * 120 + 60,
            vx: (Math.random() - 0.5) * 0.3,
            vy: (Math.random() - 0.5) * 0.3,
            hue: Math.random() * 60 + 240, // purple-blue range
            alpha: Math.random() * 0.04 + 0.02,
        }));

        // Micro particles
        const particles = Array.from({ length: 40 }, () => ({
            x: Math.random() * canvas.width,
            y: Math.random() * canvas.height,
            vx: (Math.random() - 0.5) * 0.2,
            vy: -Math.random() * 0.3 - 0.1,
            r: Math.random() * 1.5 + 0.3,
            alpha: Math.random() * 0.4 + 0.1,
            life: Math.random() * 200 + 100,
            maxLife: 300,
        }));

        const draw = () => {
            ctx.clearRect(0, 0, canvas.width, canvas.height);

            // Draw orbs
            orbs.forEach(o => {
                o.x += o.vx;
                o.y += o.vy;
                if (o.x < -o.r) o.x = canvas.width + o.r;
                if (o.x > canvas.width + o.r) o.x = -o.r;
                if (o.y < -o.r) o.y = canvas.height + o.r;
                if (o.y > canvas.height + o.r) o.y = -o.r;

                const gradient = ctx.createRadialGradient(o.x, o.y, 0, o.x, o.y, o.r);
                gradient.addColorStop(0, `hsla(${o.hue}, 70%, 60%, ${o.alpha})`);
                gradient.addColorStop(1, `hsla(${o.hue}, 70%, 60%, 0)`);
                ctx.beginPath();
                ctx.arc(o.x, o.y, o.r, 0, Math.PI * 2);
                ctx.fillStyle = gradient;
                ctx.fill();
            });

            // Draw particles
            particles.forEach(p => {
                p.x += p.vx;
                p.y += p.vy;
                p.life--;

                if (p.life <= 0) {
                    p.x = Math.random() * canvas.width;
                    p.y = canvas.height + 10;
                    p.life = p.maxLife;
                    p.alpha = Math.random() * 0.4 + 0.1;
                }

                const fade = p.life / p.maxLife;
                ctx.beginPath();
                ctx.arc(p.x, p.y, p.r, 0, Math.PI * 2);
                ctx.fillStyle = `rgba(189, 147, 249, ${p.alpha * fade})`;
                ctx.fill();
            });

            animId = requestAnimationFrame(draw);
        };
        draw();

        return () => {
            cancelAnimationFrame(animId);
            window.removeEventListener('resize', resize);
        };
    }, []);

    return <canvas ref={canvasRef} className="dashboard-vfx-canvas" />;
};

/* ΓöÇΓöÇ Collapsible Section ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ */
const CollapsibleSection = ({ title, icon, children, defaultOpen = false }) => {
    const [open, setOpen] = useState(defaultOpen);

    return (
        <div className={`collapsible-section ${open ? 'open' : ''}`}>
            <button className="collapsible-header" onClick={() => setOpen(!open)}>
                <span className="collapsible-title">
                    {icon}
                    {title}
                </span>
                {open ? <ChevronDown size={14} /> : <ChevronRight size={14} />}
            </button>
            {open && (
                <div className="collapsible-body vfx-slide-in">
                    {children}
                </div>
            )}
        </div>
    );
};

/* ΓöÇΓöÇ Dashboard ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ */
const Dashboard = () => {
    const navigate = useNavigate();
    const [status, setStatus] = useState('Idle');
    const [scanData, setScanData] = useState([]);
    const [selectedPatient, setSelectedPatient] = useState(null);
    const [analysisResult, setAnalysisResult] = useState(null);

    const handleStartScan = async () => {
        if (!selectedPatient) {
            toast.error("Select a patient first");
            return;
        }
        try {
            setStatus('Requesting Scan...');
            const response = await fetch(`${API}/scan/start`, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ patientId: selectedPatient.id })
            });
            const data = await response.json();
            setStatus(data.message);
            setScanData(prev => [...prev, `[${new Date().toLocaleTimeString()}] ${data.message}`]);
            toast.success('Scan initiated');
        } catch (error) {
            console.error("Error starting scan:", error);
            setStatus('Error: Backend Offline');
            setScanData(prev => [...prev, `[${new Date().toLocaleTimeString()}] Error: Backend Offline`]);
            toast.error('Backend is offline');
        }
    };

    const handleAnalyze = async () => {
        if (!selectedPatient) {
            toast.error("Select a patient first");
            return;
        }
        try {
            setStatus('Analyzing...');
            const response = await fetch(`${API}/scan/analyze`, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ patientId: selectedPatient.id })
            });
            const data = await response.json();
            setStatus('Analysis Complete');
            setAnalysisResult(data.analysis);
            setScanData(prev => [...prev, `[${new Date().toLocaleTimeString()}] Analysis: ${data.analysis.status}`]);
            toast.success(`Analysis complete: ${data.analysis.status}`);
        } catch (error) {
            console.error("Analysis error:", error);
            setStatus('Error: Analysis Failed');
            toast.error('Analysis failed');
        }
    };

    const handleStopScan = async () => {
        setStatus('Idle');
        setScanData(prev => [...prev, `[${new Date().toLocaleTimeString()}] Scan Stopped`]);
        toast('Scan stopped', { icon: 'ΓÅ╣' });
    };

    const handleSelectPatient = (patient) => {
        setSelectedPatient(patient);
        toast.success(`Selected: ${patient.name}`);
    };

    const handleViewProfile = (patientId) => {
        navigate(`/patients/${patientId}`);
    };

    const getStatusClass = () => {
        const s = status.toLowerCase();
        if (s.includes('error')) return 'error';
        if (s.includes('scan') || s.includes('running')) return 'scanning';
        if (s.includes('analyz')) return 'analyzing';
        if (s.includes('analysis') || s.includes('complete')) return 'analysis';
        return 'idle';
    };

    return (
        <div className="dashboard-container">
            {/* Ambient VFX Background */}
            <AmbientVFX />

            {/* Subtle scanline overlay */}
            <div className="dashboard-scanline-overlay" />

            <header className="dashboard-header vfx-fade-in">
                <div>
                    <h1>Vibrana Overseer</h1>
                    {selectedPatient && <div className="patient-badge">ΓùÅ Patient: {selectedPatient.name}</div>}
                </div>
                <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
                    <a href="/analytics" className="btn btn-ghost btn-sm">≡ƒôè Analytics</a>
                    <a href="/diagnostic-logs" className="btn btn-ghost btn-sm">≡ƒôï Logs</a>
                    <a href="/api-docs" className="btn btn-ghost btn-sm">≡ƒôû API</a>
                    <a href="/plugins" className="btn btn-ghost btn-sm">≡ƒº⌐ Plugins</a>
                    <a href="/settings" className="btn btn-ghost btn-sm">ΓÜÖ∩╕Å</a>
                    <span className={`status-badge ${getStatusClass()}`}>{status}</span>
                </div>
            </header>

            <StatsWidgets />

            <main className="dashboard-content">
                <div className="left-panel vfx-card-enter" style={{ animationDelay: '0.1s' }}>
                    <LiveMonitor />
                </div>
                <div className="right-panel">
                    <div className="vfx-card-enter" style={{ animationDelay: '0.15s' }}>
                        <PatientManager
                            onSelectPatient={handleSelectPatient}
                            onViewProfile={handleViewProfile}
                            selectedPatientId={selectedPatient?.id}
                        />
                    </div>
                    <div className="vfx-card-enter" style={{ animationDelay: '0.2s' }}>
                        <ControlPanel
                            onStart={handleStartScan}
                            onStop={handleStopScan}
                            onAnalyze={handleAnalyze}
                            status={status}
                        />
                    </div>

                    {analysisResult && (
                        <div className="analysis-card vfx-card-enter" key={Date.now()}>
                            <h4>{analysisResult.organ_name}</h4>
                            <p className="status-text">{analysisResult.status} ΓÇó {analysisResult.total_points} points</p>
                            <div className="entropy-grid">
                                {Object.entries(analysisResult.counts).map(([lvl, count]) => (
                                    <div key={lvl} className={`entropy-item lvl-${lvl}`}>
                                        <span>Lvl {lvl}</span>
                                        <strong>{count}</strong>
                                    </div>
                                ))}
                            </div>
                        </div>
                    )}

                    {/* Collapsible: Live Analysis */}
                    <div className="vfx-card-enter" style={{ animationDelay: '0.25s' }}>
                        <CollapsibleSection title="Live Analysis" icon={<Activity size={14} />} defaultOpen={false}>
                            <LiveEntropyCounter patientId={selectedPatient?.id} />
                            <ScreenWatcherPanel patientId={selectedPatient?.id} />
                        </CollapsibleSection>
                    </div>

                    {/* Collapsible: Advanced Tools */}
                    <div className="vfx-card-enter" style={{ animationDelay: '0.3s' }}>
                        <CollapsibleSection title="Advanced Tools" icon={<Wrench size={14} />} defaultOpen={false}>
                            <CVTools />
                            <MacroManager />
                        </CollapsibleSection>
                    </div>

                    {/* Scan Log */}
                    <div className="data-log vfx-card-enter" style={{ animationDelay: '0.35s' }}>
                        <h3>Scan Log</h3>
                        <ul>
                            {scanData.map((log, idx) => <li key={idx}>{log}</li>)}
                            {scanData.length === 0 && <li className="log-empty">No data yet...</li>}
                        </ul>
                    </div>
                </div>
            </main>
        </div>
    );
};

export default Dashboard;

