import React, { useState, useEffect, useRef } from 'react';
import { LOCAL_API as API } from '../config.js';

const LiveMonitor = () => {
    const [feedError, setFeedError] = useState(true);
    const [feedKey, setFeedKey] = useState(Date.now());
    const [isHovered, setIsHovered] = useState(false);
    const [uptime, setUptime] = useState(0);
    const containerRef = useRef(null);

    const handleFeedError = () => setFeedError(true);
    const retryFeed = () => {
        setFeedKey(Date.now());
        setFeedError(false);
    };

    // Uptime counter
    useEffect(() => {
        const interval = setInterval(() => setUptime(prev => prev + 1), 1000);
        return () => clearInterval(interval);
    }, []);

    const formatUptime = (s) => {
        const h = Math.floor(s / 3600);
        const m = Math.floor((s % 3600) / 60);
        const sec = s % 60;
        return `${h.toString().padStart(2, '0')}:${m.toString().padStart(2, '0')}:${sec.toString().padStart(2, '0')}`;
    };

    return (
        <div
            className="live-monitor"
            ref={containerRef}
            onMouseEnter={() => setIsHovered(true)}
            onMouseLeave={() => setIsHovered(false)}
        >
            {/* Header with live indicator */}
            <div className="monitor-header">
                <h2>
                    <span className="monitor-live-dot" />
                    Live NLS Feed
                </h2>
                <div className="monitor-meta">
                    <span className="monitor-uptime">{formatUptime(uptime)}</span>
                    <span className="monitor-res">1920x1080</span>
                </div>
            </div>

            {/* Screen with effects */}
            <div className="monitor-screen">
                {feedError ? (
                    <div className="monitor-offline" onClick={retryFeed}>
                        <div className="monitor-offline-icon">
                            <svg width="48" height="48" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5">
                                <path d="M2 12s3-7 10-7 10 7 10 7-3 7-10 7-10-7-10-7Z" />
                                <circle cx="12" cy="12" r="3" />
                                <line x1="2" y1="2" x2="22" y2="22" strokeWidth="2" />
                            </svg>
                        </div>
                        <span className="monitor-offline-text">Feed Offline</span>
                        <span className="monitor-offline-hint">Click to reconnect</span>
                    </div>
                ) : (
                    <>
                        <img
                            src={`${API}/video_feed?t=${feedKey}`}
                            alt="Live NLS Feed"
                            className="monitor-feed-img"
                            onError={handleFeedError}
                        />
                        {/* Scan line effect */}
                        <div className="monitor-scanline" />
                        {/* Corner markers */}
                        <div className="monitor-corner tl" />
                        <div className="monitor-corner tr" />
                        <div className="monitor-corner bl" />
                        <div className="monitor-corner br" />
                        {/* Recording indicator */}
                        <div className="monitor-rec">
                            <span className="monitor-rec-dot" />
                            REC
                        </div>
                    </>
                )}

                {/* Hover overlay */}
                {isHovered && !feedError && (
                    <div className="monitor-overlay">
                        <span>NLS Bioresonance - Real-time Analysis</span>
                    </div>
                )}
            </div>
        </div>
    );
};

export default LiveMonitor;

